// ---------- safe node accessor ----------
// $node["NodeName"] throws a read-only Error if the node hasn't executed.
// Optional chaining (?.) does NOT catch this — we need try/catch.
const safeNode = (name) => {
  try {
    return $node[name]?.json || null;
  } catch (e) {
    return null;
  }
};

// ---------- helpers ----------
const first = (...v) => v.find(x => x !== undefined && x !== null && x !== "");
const cleanReply = (s) =>
  String(s || "")
    .replace(/<CONTROL>[\s\S]*?<\/CONTROL>/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .trim();
const normWa = (x) => {
  if (!x) return "";
  const s = String(x).trim();
  const plus = s.startsWith("+") ? "+" : "";
  const digits = s.replace(/[^\d]/g, "");
  return (plus + digits) || "";
};
const asNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

// ---------- detect gate action ----------
const gateAction = $json.action === "hold" ? "hold" : "send";

// ---------- pull inbound from Post-process ----------
const P = safeNode("Post-process") || {};
const seen = P.lastSeen || {};
const ctx  = P.context  || {};

const wa_id = normWa(first(
  seen.wa_id, P.wa_id, ctx.wa_id,
  $json.wa_id, $json.patch?.wa_id, $json.context?.wa_id
));
const inboundTsMs = asNum(first(
  seen.lastMessageTs, P.tsMs, $json.tsMs, $json.fields?.tsMs?.integerValue
));

if (!wa_id || inboundTsMs === null) {
  throw new Error(`cust+system log: missing wa_id (${wa_id}) or inboundTsMs (${inboundTsMs}). Check Post-process.`);
}
const docid = `${wa_id}_${inboundTsMs}`;

// ---------- inbound snapshot ----------
const inboundDirection = String(first(seen.lastDirection, "inbound")).toLowerCase();
const inboundText      = String(first(seen.lastText, $json.text, ""));
const inboundTsIso     = String(first(seen.lastMessageAtIso, new Date(inboundTsMs).toISOString()));
const inboundTtlIso    = new Date(inboundTsMs + 120*24*3600*1000).toISOString();

const inboundFields = {
  wa_id:       { stringValue: String(wa_id) },
  direction:   { stringValue: inboundDirection },
  inboundtext: { stringValue: inboundText },
  tsMs:        { integerValue: String(inboundTsMs) },
  tsIso:       { timestampValue: inboundTsIso },
  ttlExpireAt: { timestampValue: inboundTtlIso },
  docid:       { stringValue: docid },
};

// ---------- outbound (reply) ----------
// safeNode() returns null for unexecuted nodes instead of throwing
const codeNodeJson        = safeNode("Code in JavaScript");
const setOutboundJson     = safeNode("SetOutboundText_WABA");
const neeemaAgentJson     = safeNode("Neema AI Agent");

const reply = cleanReply(first(
  P.reply_text,
  $json.reply_text,
  $json.output,
  codeNodeJson?.reply_text,
  codeNodeJson?.output,
  setOutboundJson?.reply_text,
  neeemaAgentJson?.output,
  ""
));

const nowMs  = Date.now();
const nowIso = new Date(nowMs).toISOString();

const outboundFields = {
  outbound:      { stringValue: "outbound" },
  outbound_text: { stringValue: reply },
  outboundTs:    { stringValue: String(nowMs) },
  outboundIso:   { timestampValue: nowIso },
  gate_action:   { stringValue: gateAction },
  held:          { booleanValue: gateAction === "hold" },
  sent:          { booleanValue: gateAction === "send" },
};

// ---------- updateMask ----------
const updateMaskFields = [
  "wa_id", "direction", "text", "tsMs", "tsIso", "ttlExpireAt", "docid",
  "outbound", "outbound_text", "outboundTs", "outboundIso",
  "gate_action", "held", "sent",
];

// ---------- emit ----------
return [{
  json: {
    wa_id,
    docid,
    gate_action: gateAction,
    inboundFields,
    outboundFields,
    updateMaskFields,
  }
}];

// Last Order + Prep Patch — Confirmed-only edition
// ONLY creates an order event when orderPlaced === true (customerExplicitlyConfirmed).
// Does NOT fall back to text parsing, previous cart, or upstream item lists.
// Items must come exclusively from Post-process (which already validated the gates).

const J = $json || {};
const ctx   = J.context || {};
const seen  = J.lastSeen || {};
const nowIso = () => new Date().toISOString();
const n = (v, d = 0) => (Number.isFinite(+v) ? +v : d);

const fStr = v => (v == null ? undefined : ({ stringValue: String(v) }));
const fInt = v => (v == null || v === '' || !Number.isFinite(+v) ? undefined : { integerValue: String(Math.trunc(+v)) });
const fTs  = v => ({ timestampValue: new Date(v ?? Date.now()).toISOString() });
const toFs = v => Array.isArray(v)
  ? { arrayValue: { values: v.map(toFs) } }
  : v === null
    ? { nullValue: null }
    : typeof v === 'object'
      ? { mapValue: { fields: Object.fromEntries(Object.entries(v).map(([k,val]) => [k, toFs(val)])) } }
      : (typeof v === 'number'
          ? (Number.isInteger(v) ? { integerValue: String(v) } : { doubleValue: v })
          : (typeof v === 'boolean' ? { booleanValue: v } : { stringValue: String(v) }));

const wa_id = J.wa_id || ctx.wa_id || seen.wa_id || J.patch?.wa_id || null;
if (!wa_id) throw new Error('Last Order + Prep Patch: wa_id missing');

// ── Order placement gate ──────────────────────────────────────
// Post-process sets orderPlaced = true ONLY when customerExplicitlyConfirmed = true
// AND requiresClarification = false AND isDuplicateOrder = false.
const orderPlaced                 = J.orderPlaced === true;
const customerExplicitlyConfirmed = J.customerExplicitlyConfirmed === true || J.flags?.customerExplicitlyConfirmed === true;
const requiresClarification       = J.requiresClarification === true || J.flags?.requiresClarification === true;
const isDuplicateOrder            = J.isDuplicateOrder === true || J.flags?.isDuplicateOrder === true;

// Triple-check: all three gates must pass for order to be real
const effectiveOrderPlaced = orderPlaced && customerExplicitlyConfirmed && !requiresClarification && !isDuplicateOrder;

const baseTsMs = n(J.tsMs ?? seen.lastMessageTs, Date.now());
const sessionId = `${wa_id}_${Math.floor(baseTsMs / 1000)}`;

// ── Items: ONLY from Post-process confirmed output ────────────
// No text parsing. No previous cart fallback.
const normItem = i => {
  if (!i || typeof i !== 'object') return null;
  const qty  = Math.max(n(i.qty ?? i.quantity ?? 1, 1), 1);
  const unit = n(i.price ?? i.unit ?? i.unit_price ?? 0, 0);
  const name = String(i.name || i.product || i.title || 'item');
  const total = n(i.total, qty * unit);
  const sku = i.sku ?? null;
  return { name, qty, unit, total, ...(sku ? { sku } : {}) };
};

let items = [];
if (effectiveOrderPlaced) {
  const confirmedItems = J.order_event?.items || J.items_added || [];
  items = Array.isArray(confirmedItems)
    ? confirmedItems.map(normItem).filter(i => i && n(i.unit, 0) > 0)
    : [];
}

const subtotal = items.reduce((s, it) => s + n(it.total, n(it.qty,0)*n(it.unit,0)), 0);

const evtIn = J.order_event || {};
const order_event = {
  eventType: effectiveOrderPlaced
    ? (evtIn.eventType || 'order.placed')
    : 'order.snapshot',
  status: effectiveOrderPlaced ? 'pending' : 'open',
  items: effectiveOrderPlaced ? items : [],
  subtotal: effectiveOrderPlaced ? subtotal : 0,
  tsIso: nowIso(),
  channel: evtIn.channel || 'whatsapp',
  source:  evtIn.source  || 'ai_agent',
  sessionId: evtIn.sessionId || sessionId,
  order_id:  evtIn.order_id  || sessionId,
  isNewOrder: evtIn.isNewOrder ?? effectiveOrderPlaced,
  customerExplicitlyConfirmed,
  requiresClarification,
  isDuplicateOrder,
};

const lastOrder = {
  found: effectiveOrderPlaced && items.length > 0,
  wa_id,
  updatedAt: nowIso(),
  order_id: order_event.order_id,
  sessionId: order_event.sessionId,
  channel: order_event.channel,
  source: order_event.source,
  lastText:         seen.lastText ?? J.text ?? J.msgText ?? '',
  lastDirection:    seen.lastDirection ?? ctx.lastDirection ?? J.direction ?? 'inbound',
  lastMessageTs:    n(seen.lastMessageTs ?? J.tsMs, baseTsMs),
  lastMessageAtIso: seen.lastMessageAtIso ?? J.tsIso ?? new Date(baseTsMs).toISOString(),
  isReturning: !!J.isReturning,
  currency: 'KES',
  subtotal: order_event.subtotal,
  status: order_event.status,
  paymentStatus: 'unpaid',
  fulfillmentStatus: effectiveOrderPlaced ? 'pending' : 'none',
  items: order_event.items,
};

const stateCart = { subtotal: order_event.subtotal };
if (order_event.items.length) stateCart.items = order_event.items;
const state = { active: 'active', cart: stateCart };

const firestoreBody = {
  fields: {
    wa_id: fStr(wa_id),
    sessionId: fStr(order_event.sessionId),
    order_id: fStr(order_event.order_id),
    eventType: fStr(order_event.eventType),
    channel: fStr(order_event.channel),
    source:  fStr(order_event.source),
    lastText:         fStr(lastOrder.lastText || ''),
    lastDirection:    fStr(lastOrder.lastDirection || 'inbound'),
    lastMessageTs:    fInt(lastOrder.lastMessageTs),
    lastMessageAtIso: fTs(lastOrder.lastMessageAtIso),
    isReturning: { booleanValue: !!J.isReturning },
    ...(order_event.items.length ? { items: toFs(order_event.items) } : {}),
    subtotal:          fInt(order_event.subtotal),
    currency:          fStr('KES'),
    replyText:         fStr(J.reply_text || J.output || ''),
    tsIso:             fTs(order_event.tsIso),
    updatedAt:         fTs(Date.now()),
    status:            fStr(lastOrder.status),
    paymentStatus:     fStr(lastOrder.paymentStatus),
    fulfillmentStatus: fStr(lastOrder.fulfillmentStatus),
    state: toFs(state),
  }
};

const docid = `${wa_id}_${Math.floor(baseTsMs / 1000)}`;
if (!docid || String(docid).startsWith('unknown_')) {
  throw new Error(`OrderEvent Upsert: bad docid="${docid}"`);
}

return [{
  ...J,
  wa_id,
  items_added: order_event.items,
  lastOrder,
  order_event,
  docid,
  firestoreBody,
  orderPlaced: effectiveOrderPlaced,
  customerExplicitlyConfirmed,
  requiresClarification,
  isDuplicateOrder,
  mergeKey: J.mergeKey ?? 1,
}];

// Format Input Data
// Sits between: Last Order + Prep Patch → Upsert Order Event API
// Shapes the payload the API receives for every order event.
// Added: is_new_order, is_duplicate_order, customer_explicitly_confirmed,
//        requires_clarification — needed by the API to INSERT vs UPSERT
//        and to audit gate state per order event.

const d = $input.first().json;

return [{
  json: {
    wa_id:              d.wa_id,

    // Order identity
    session_id:         d.order_event?.sessionId         ?? null,
    event_type:         d.order_event?.eventType         ?? null,
    // Possible values:
    //   "order.placed"     → new confirmed order (INSERT)
    //   "order.updated"    → same products, qty/detail changed (UPSERT)
    //   "order.item.added" → items building up, not yet confirmed
    //   "order.snapshot"   → no items, context-only snapshot

    // API uses is_new_order to decide INSERT vs UPSERT
    is_new_order:       d.order_event?.isNewOrder        ?? true,

    // Line items and financials
    items:              d.order_event?.items             ?? [],
    subtotal:           parseFloat(d.order_event?.subtotal ?? 0),
    currency:           d.lastOrder?.currency            ?? "KES",

    // Order lifecycle status
    status:             d.lastOrder?.status              ?? "open",
    payment_status:     d.lastOrder?.paymentStatus       ?? "unpaid",
    fulfillment_status: d.lastOrder?.fulfillmentStatus   ?? "pending",

    // Message context
    reply_text:         d.reply_text                     ?? null,
    channel:            d.order_event?.channel           ?? "whatsapp",

    // Cart state snapshot (persisted to user record)
    state: d.lastSeen?.state ?? {
      active: "active",
      cart: { items: [], subtotal: 0 },
    },

    // ── Gate audit fields ─────────────────────────────────────
    // These let the API and any downstream dashboards understand
    // why an event was written and what its validity state is.

    // true  → a duplicate was detected; API should NOT create a new order
    is_duplicate_order:            d.isDuplicateOrder            ?? false,

    // true  → customer sent an explicit affirmative (yes/confirm/sawa/ndio etc.)
    // false → order was built but not yet confirmed by customer
    customer_explicitly_confirmed: d.customerExplicitlyConfirmed ?? false,

    // true  → item was ambiguous (e.g. plain "cups"); clarification still pending
    // When true, event_type will be "order.snapshot" with no items
    requires_clarification:        d.requiresClarification       ?? false,
  },
}];
